/**
 * Self-contained (no-network) assets for the serverless sermon PDF render (ICR-114).
 *
 * The Chromium render for the regen webhook/cron runs with no outbound network access
 * (see renderSermonPdf.ts), so the two brand fonts + the church logo are embedded here
 * as base64 and injected as data-URIs instead of the Google Fonts `<link>` the local
 * pipeline (.claude/scripts/predica/build-predica-pdf.mjs) still uses over the network.
 *
 * Font source: the exact "latin" subset files Google Fonts serves for the weights
 * buildPdfHtml uses (helpers.ts), fetched once from the same
 * `https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;0,700;1,400&family=Outfit:wght@300;400;500;600`
 * stylesheet the local pipeline requests, then downloaded from the `@font-face` `src`
 * URLs on fonts.gstatic.com (OFL-licensed). Both families ship as variable fonts, so a
 * single file per style covers a weight RANGE:
 *   - Outfit (normal, wght 300–600)             → one variable file
 *   - Playfair Display (normal, wght 400–700)   → one variable file
 *   - Playfair Display (italic, wght 400 only)  → one static file
 *
 * Logo source: public/assets/img/redentor_logo.png (already committed; re-inlined here
 * so the render never touches the filesystem at request time).
 *
 * DO NOT hand-edit the base64 strings below. Regenerate by re-downloading the same
 * three `@font-face src` URLs from the stylesheet above (or the equivalent
 * `@fontsource` package version) plus the current logo PNG, and re-running the
 * generation step documented in the ICR-114 PR description.
 */

/** Outfit variable font (latin), weights 300–600, normal style. */
export const OUTFIT_VARIABLE_LATIN_WOFF2_BASE64 =
  "";

/** Playfair Display variable font (latin), weights 400–700, normal style. */
export const PLAYFAIR_DISPLAY_NORMAL_LATIN_WOFF2_BASE64 =
  "";

/** Playfair Display (latin), weight 400, italic style only. */
export const PLAYFAIR_DISPLAY_ITALIC_400_LATIN_WOFF2_BASE64 =
  "";

/** The church logo (PNG), inlined as a data URI for the PDF cover. */
export const LOGO_PNG_DATA_URI = "data:image/png;base64,";
